// Extract source IP from the Wazuh alert + allowlist safety check
const alert = $('Webhook').first().json.body;

// pull src_ip from common Wazuh alert locations
const srcIp = alert?.data?.src_ip 
           || alert?.data?.srcip 
           || alert?.data?.win?.eventdata?.sourceIp 
           || null;

// --- SAFETY: infrastructure allowlist (NEVER block these) ---
const ALLOWLIST = {
  "10.10.10.1":  "pfSense gateway",
  "10.10.10.10": "siem (SIEM + n8n)",
  "10.10.10.2":  "ThinkPad host"
};

let decision;
if (!srcIp) {
  decision = { action: "skip", reason: "no_src_ip", src_ip: null };
} else if (ALLOWLIST[srcIp]) {
  decision = { action: "refused", reason: "allowlist", src_ip: srcIp, detail: ALLOWLIST[srcIp] };
} else {
  decision = { action: "allow_block", reason: "passed_safety", src_ip: srcIp };
}

return [{
  json: {
    ...alert,
    soar_decision: decision,
    rule_id: alert?.rule?.id,
    rule_level: alert?.rule?.level,
    rule_desc: alert?.rule?.description,
    mitre: alert?.rule?.mitre?.id
  }
}];

// ============================================================
//  SOC Investigation Ticket Builder — professional, TheHive-ready
//  Enrichment fields are placeholders, populated by Cortex in 6-B
// ============================================================
const d = $('Code in JavaScript').first().json;
const now = new Date();
const pad = n => String(n).padStart(2, "0");

// ---- severity + SLA mapping from Wazuh level ----
const lvl = d.rule_level || 0;
let severity, tlp, slaHours;
if (lvl >= 13)      { severity = "Critical"; tlp = "RED";    slaHours = 1;  }
else if (lvl >= 10) { severity = "High";     tlp = "AMBER";  slaHours = 4;  }
else if (lvl >= 7)  { severity = "Medium";   tlp = "GREEN";  slaHours = 24; }
else                { severity = "Low";      tlp = "WHITE";  slaHours = 72; }

const slaDue = new Date(now.getTime() + slaHours * 3600 * 1000);

// ---- identifiers ----
const dateKey = `${now.getUTCFullYear()}${pad(now.getUTCMonth()+1)}${pad(now.getUTCDate())}`;
const timeKey = `${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}${pad(now.getUTCSeconds())}`;
const ticketKey = `SOC-${dateKey}-${timeKey}`;

// ---- pull fields ----
const srcIp   = d.soar_decision?.src_ip || d.data?.src_ip || "unknown";
const dstDom  = d.parent_domain || d.data?.parent_domain || "N/A";
const qCount  = d.query_count || d.data?.query_count || "N/A";
const mitreArr= Array.isArray(d.mitre) ? d.mitre : (d.mitre ? [d.mitre] : []);
const mitre   = mitreArr.join(", ") || "N/A";
const action  = d.soar_decision?.action || "none";
const reason  = d.soar_decision?.reason || "N/A";

// ---- human summary ----
const summary = `[${severity}] ${d.rule_desc || "Security alert"} — host ${srcIp}`;

// ---- contained? ----
const contained = action === "allow_block";
const actionText = contained
  ? `Host ${srcIp} automatically isolated (added to pfSense soar_blocklist, firewall block applied).`
  : `No automated block. Reason: ${reason}${reason === "allowlist" ? " (protected infrastructure)" : ""}.`;

// ---- Markdown description (renders nicely in TheHive) ----
const description = `
## Executive Summary
A **${severity.toLowerCase()}**-severity detection fired on the network. ${d.rule_desc || ""}.
Automated containment: **${contained ? "APPLIED" : "NOT APPLIED"}**.

## Detection Details
| Field | Value |
|---|---|
| Rule | ${d.rule_id} — ${d.rule_desc} |
| Wazuh Level | ${lvl} |
| MITRE ATT&CK | ${mitre} |
| Source Host | \`${srcIp}\` |
| Destination | \`${dstDom}\` |
| Observed Count | ${qCount} |
| Detection Time | ${d.timestamp || now.toISOString()} |

## Impact / Affected Assets
- **Primary asset:** ${srcIp} (internal endpoint)
- **Containment status:** ${contained ? "Isolated" : "Active — review required"}

## Automated Response
${actionText}
`.trim();

// ---- the full ticket object ----
const ticket = {
  // === HEADER ===
  ticket_key:   ticketKey,
  summary:      summary,
  type:         "Security Incident",
  status:       "Open",
  priority:     severity,
  tlp:          tlp,
  created_utc:  now.toISOString(),
  reporter:     "Wazuh SOAR (automated)",
  assignee:     "unassigned",
  sla_due_utc:  slaDue.toISOString(),
  sla_hours:    slaHours,
  labels:       [...mitreArr, contained ? "auto-contained" : "needs-review",
                 severity.toLowerCase(), "network-detection"],

  // === DESCRIPTION (markdown) ===
  description:  description,

  // === MITRE ===
  mitre: {
    techniques: mitreArr,
    tactic_hint: "See ATT&CK mapping for kill-chain phase"
  },

  // === OBSERVABLES (TheHive-style, ready for Cortex) ===
  observables: [
    { type: "ip",     value: srcIp,  role: "source",      ioc: false, note: "internal endpoint" },
    { type: "domain", value: dstDom, role: "destination", ioc: true,  note: "suspected C2 / beaconing target" }
  ],

  // === TIMELINE ===
  timeline: [
    { time: d.timestamp || now.toISOString(), event: `Detection fired: ${d.rule_id} ${d.rule_desc}` },
    { time: now.toISOString(),                event: `SOAR decision: ${action} (${reason})` },
    { time: now.toISOString(),                event: contained ? `Containment applied: ${srcIp} isolated` : `No containment: ${reason}` }
  ],

  // === AUTOMATED RESPONSE ===
  automated_response: {
    decision:     action,
    reason:       reason,
    action_taken: actionText,
    contained:    contained,
    allowlist_protected: action === "refused" && reason === "allowlist"
  },

  // === ENRICHMENT (Cortex — populated in 6-B) ===
  enrichment: {
    status: "pending",
    virustotal:  { domain: dstDom, verdict: null, malicious_count: null, checked: false },
    abuseipdb:   { ip: srcIp,      score: null,   checked: false },
    note: "Awaiting Cortex analyzers (VirusTotal, AbuseIPDB) — Phase 6-B"
  },

  // === INVESTIGATION TASKS (L1, MITRE-guided) ===
  investigation_tasks: [
    { id: 1, task: "Verify source host identity & ownership",              status: "todo", owner: "L1" },
    { id: 2, task: "Determine if activity is expected (baseline/whitelist)", status: "todo", owner: "L1" },
    { id: 3, task: "Review Cortex enrichment verdicts on destination",     status: "todo", owner: "L1" },
    { id: 4, task: "Pivot: search other hosts for same IOC/pattern",       status: "todo", owner: "L1" },
    { id: 5, task: "Examine host process/parent chain at detection time",  status: "todo", owner: "L1" },
    { id: 6, task: "Confirm containment effective (host reachability)",    status: "todo", owner: "L1" },
    { id: 7, task: "Escalate to L2 or resolve with justification",         status: "todo", owner: "L1" }
  ],

  // === ANALYST WORKSPACE ===
  work_notes:  [],                    // analyst appends: {time, author, note}
  disposition: "PENDING",             // TruePositive | FalsePositive | Escalated
  resolution:  "",                    // final summary on close

  // === REFERENCE ===
  playbook: `PICERL for ${mitre}: Prepare → Identify → Contain (${contained ? "auto-done" : "manual"}) → Eradicate → Recover → Lessons`,
  runbook_url: "https://github.com/AJahmadcyber/homelab-mdr"
};

return [{ json: ticket }];
